class Solution:
    def kthSmallest(self, par, vals, queries):
        n = len(vals)
        children = [[] for _ in range(n)]
        root = 0
        for i in range(n):
            if par[i] == -1:
                root = i
            else:
                children[par[i]].append(i)
        from collections import deque
        pathxor = [0] * n
        pathxor[root] = vals[root]
        dq = deque([root])
        while dq:
            u = dq.popleft()
            for c in children[u]:
                pathxor[c] = pathxor[u] ^ vals[c]
                dq.append(c)
        def subtree(u):
            res = []
            st = [u]
            while st:
                x = st.pop()
                res.append(x)
                for c in children[x]:
                    st.append(c)
            return res
        ans = []
        for (u, k) in queries:
            dist = sorted({pathxor[x] for x in subtree(u)})
            ans.append(dist[k - 1] if k - 1 < len(dist) else -1)
        return ans

