        from collections import deque
        pathxor = [0] * n
        pathxor[root] = vals[root]
        dq = deque([root])
        while dq:
            u = dq.popleft()
            for c in children[u]:
                pathxor[c] = pathxor[u] ^ vals[c]
                dq.append(c)
        qby = [[] for _ in range(n)]
        for idx, (u, k) in enumerate(queries):
            qby[u].append((k, idx))
        ans = [0] * len(queries)
        sets = [None] * n
        st = [(root, False)]
        while st:
            node, processed = st.pop()
            if processed:
                best = {pathxor[node]}
                for c in children[node]:
                    s = sets[c]
                    if len(s) > len(best):
                        best, s = s, best
                    best.update(s)
                    sets[c] = None
                sets[node] = best
                if qby[node]:
                    arr = sorted(best)
                    for (k, idx) in qby[node]:
                        ans[idx] = arr[k - 1] if k - 1 < len(arr) else -1
            else:
                st.append((node, True))
                for c in children[node]:
                    st.append((c, False))
        return ans

