var kthSmallest = function(par, vals, queries) {
    const n = vals.length;
    const children = Array.from({length: n}, () => []);
    let root = 0;
    for (let i = 0; i < n; i++) {
        if (par[i] === -1) root = i; else children[par[i]].push(i);
    }
    const pathxor = new Array(n).fill(0);
    pathxor[root] = vals[root];
    let q = [root];
    while (q.length) {
        const next = [];
        for (const u of q) {
            for (const c of children[u]) { pathxor[c] = pathxor[u] ^ vals[c]; next.push(c); }
        }
        q = next;
    }
    const qby = Array.from({length: n}, () => []);
    for (let idx = 0; idx < queries.length; idx++) {
        qby[queries[idx][0]].push([queries[idx][1], idx]);
    }
    const ans = new Array(queries.length).fill(0);
    const sets = new Array(n).fill(null);
    const st = [[root, false]];
    while (st.length) {
        const [node, processed] = st.pop();
        if (processed) {
            let best = new Set([pathxor[node]]);
            for (const c of children[node]) {
                let s = sets[c];
                if (s.size > best.size) { const tmp = best; best = s; s = tmp; }
                for (const v of s) best.add(v);
                sets[c] = null;
            }
            sets[node] = best;
            if (qby[node].length) {
                const arr = Array.from(best).sort((a, b) => a - b);
                for (const [k, idx] of qby[node]) {
                    ans[idx] = (k - 1 < arr.length) ? arr[k - 1] : -1;
                }
            }
        } else {
            st.push([node, true]);
            for (const c of children[node]) st.push([c, false]);
        }
    }
    return ans;
};
